function fb(a, b) { if (a) { return a; } return b; }
var topic = fb($.input.researchTopic, '');
var depth = fb($.input.depth, 'standard');

var queryCount = 5;
if (depth === 'quick') queryCount = 3;
if (depth === 'deep') queryCount = 8;

var prompt = 'Generate ' + queryCount + ' diverse search queries to thoroughly research the following topic. Each query should explore a different angle.\n\n';
prompt += 'TOPIC: ' + topic + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{ "queries": ["query 1", "query 2"] }';

return { prompt: prompt, topic: topic, depth: depth, queryCount: queryCount };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiGenerateQueries.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try {
  var parsed = JSON.parse(raw);
  return { queries: fb(parsed.queries, []) };
} catch(e) {
  return { queries: [$.input.researchTopic] };
}

function fb(a, b) { if (a) { return a; } return b; }
var results = fb(fb($.steps.searchExa.response, {}).results, []);
var urls = [];
results.slice(0, 3).forEach(function(r) {
  if (r.url) urls.push(r.url);
});

var searchSummary = '';
results.forEach(function(r, i) {
  searchSummary += (i + 1) + '. ' + (fb(r.title, r.url)) + '\n';
  searchSummary += '   ' + (fb(r.text, '')).slice(0, 200) + '\n\n';
});

return { urls: urls, searchSummary: searchSummary, resultCount: results.length };

function fb(a, b) { if (a) { return a; } return b; }
function gd(a, b) { if (a) { return b; } return a; }
var searchSummary = $.steps.pickTopUrls.output.searchSummary;
var urls = $.steps.pickTopUrls.output.urls;
var iterations = fb(fb($.steps.deepScrape.response, {}).iterations, []);
var topic = $.input.researchTopic;

var deepContent = '';
iterations.forEach(function(iter, i) {
  var url = fb(urls[i], 'Unknown');
  var resp = null; try { if (iter.scrapePage) { if (iter.scrapePage.response) { resp = iter.scrapePage.response.data; } } } catch(ex) { resp = null; };
  if (resp) { if (resp.markdown) {
    deepContent += '=== DEEP DIVE ' + (i + 1) + ' ===\n';
    deepContent += 'URL: ' + url + '\n';
    deepContent += resp.markdown.slice(0, 4000) + '\n\n';
  }
});

var allResearch = 'RESEARCH TOPIC: ' + topic + '\n\n';
allResearch += 'SEARCH RESULTS OVERVIEW:\n' + searchSummary + '\n';
allResearch += 'DEEP SCRAPED CONTENT:\n' + deepContent;

return { allResearch: allResearch, topic: topic };

var data = $.steps.compileResearch.output;

var prompt = 'You are a senior research analyst. Synthesize the following research data into a comprehensive, well-structured report.\n\n';
prompt += data.allResearch + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write an executive summary\n';
prompt += '- Organize findings into clear sections\n';
prompt += '- Highlight key insights and trends\n';
prompt += '- Note conflicting information from different sources\n';
prompt += '- Include recommendations and next steps\n';
prompt += '- Cite sources where applicable\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "report title",\n';
prompt += '  "executiveSummary": "3-5 sentence executive summary",\n';
prompt += '  "sections": [\n';
prompt += '    { "heading": "section title", "content": "section content", "keyInsight": "main takeaway" }\n';
prompt += '  ],\n';
prompt += '  "keyFindings": ["finding 1", "finding 2"],\n';
prompt += '  "trends": ["trend 1"],\n';
prompt += '  "recommendations": ["recommendation 1"],\n';
prompt += '  "sources": [{ "title": "source title", "url": "source url", "relevance": "why it matters" }],\n';
prompt += '  "confidence": "high/medium/low",\n';
prompt += '  "gapsInResearch": ["areas that need more investigation"]\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiSynthesize.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Research Report', executiveSummary: raw, sections: [], keyFindings: [] }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseReport.output;
var topic = $.input.researchTopic;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':mag: ' + (fb(ai.title, 'Research Report')), emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Executive Summary*\n' + (fb(ai.executiveSummary, '')) } });

var confidenceIcon = ':white_circle:';
if (ai.confidence === 'high') confidenceIcon = ':large_green_circle:';
if (ai.confidence === 'medium') confidenceIcon = ':large_orange_circle:';
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceIcon + ' *Confidence:* ' + (fb(ai.confidence, 'N/A')) }] });
blocks.push({ type: 'divider' });

var sections = fb(ai.sections, []);
sections.forEach(function(s) {
  var sText = '*' + s.heading + '*\n' + (fb(s.content, '')).slice(0, 500);
  if (s.keyInsight) sText += '\n:bulb: _Key insight: ' + s.keyInsight + '_';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sText } });
});

var findings = fb(ai.keyFindings, []);
if (findings.length > 0) {
  blocks.push({ type: 'divider' });
  var findText = '*:dart: Key Findings*\n';
  findings.forEach(function(f, i) { findText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: findText } });
}

var recs = fb(ai.recommendations, []);
if (recs.length > 0) {
  var recText = '*:pushpin: Recommendations*\n';
  recs.forEach(function(r, i) { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText } });
}

var gaps = fb(ai.gapsInResearch, []);
if (gaps.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':question: *Research gaps:* ' + gaps.join(', ') }] });
}

var sources = fb(ai.sources, []);
if (sources.length > 0) {
  var srcText = '*Sources:* ';
  sources.slice(0, 5).forEach(function(s, i) {
    srcText += '<' + (fb(s.url, '#')) + '|' + (fb(s.title, 'Source ') + (i + 1)) + '> ';
  });
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: srcText }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI + One CLI' }] });

var fallback = 'Research Report: ' + (fb(ai.title, topic));
return { blocks: blocks, fallback: fallback };
